var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......진동이 멎었군.","JPN":"……振動が止まった。","ENG":"The vibrations stopped.","TWN":"……震動停止了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"느껴지는 에너지 파형으로 보면, 아마 급하게 다이브 시퀀스를 진행한 것 같은데......","JPN":"エネルギー波形からして、急ぎでダイブシーケンスを進めたようだが……","ENG":"Judging by the energy waves, they must’ve executed an emergency dive sequence...","TWN":"從感受到的能量波形來看，應該是進行了緊急躍入……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"어디로 떨어질지는 모르겠지만, 살아 돌아가려면 항해사가 운이 좋길 바라야겠군.","JPN":"どこに落下するかは測定不能。航海士の運次第で生死が決まる。","ENG":"Wherever we end up dropping, hopefully luck is on the navigator’s side... if we are to return alive.","TWN":"雖然不知道會降落到哪裡，但想要活下來的話，就得看駕駛員的運氣了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"밖의 네 동료들은 어때?","JPN":"外にいるあなたの同僚たちはどうなのですか？","ENG":"How about your colleagues out there?","TWN":"妳那些在外面的同事怎麼樣了？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"걱정되지 않나?","JPN":"気にならないのですか？","ENG":"Aren't you worried about them?","TWN":"妳不擔心嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":".....이것도 생각했던 것과는 다르군.","JPN":"……これも想定されていない事態。","ENG":"This too is different from what I expected.","TWN":"……這也和我想得不一樣啊。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"내게 물어 볼 말이 많을 줄 알았는데.","JPN":"私に聞きたいことが多いのではと思っていたが。","ENG":"I thought you’d have many questions for me.","TWN":"我還以為妳會有很多話問我。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......내가? 어째서?","JPN":"……私が？　どうして？","ENG":"Me? Why?","TWN":"……我？為什麼？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"모체의 최후에 대한 격렬한 감정반응이나, 나를 처음 봤을 때 나타낸 동요 등을 고려했을 때......","JPN":"母体の最期に対する激しい感情反応や、私を初めて見た時の動揺などから……","ENG":"Given the violent emotional response to the death of my source, and your reaction upon seeing me for the first time...","TWN":"從我母體死亡的激烈感情反應，還有妳第一次見到我的時候十分動搖……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"내 모체에 대해 궁금한 점이 많을 거라고 생각했다.","JPN":"私の母体について、知りたいことが多いのではと想定していた。","ENG":"I thought you’d have many questions about my source.","TWN":"我覺得妳會對我的母體有很多問題。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그렇다고 해도, 왜 네게 그런 걸 물어야 하지?","JPN":"だとしても、あんたにそんなことを聞いてどうする？","ENG":"Even if I did, why would I ask you about it?","TWN":"就算如此，為什麼要問妳呢？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"네 입으로 말했잖아. 넌 나래와 다른 존재라고.","JPN":"あんたの口から言ったじゃない。自分はナルミとは異なる存在だって。","ENG":"You said so yourself. You're not Narae.","TWN":"妳自己不是也說了嘛，妳不是娜拉。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"물론 그렇다. 하지만 관련이 전혀 없는 것은 아니지.","JPN":"もちろんそうだ。しかし、全く関係がないわけではない。","ENG":"Indeed. But I wouldn’t say I’m completely unrelated.","TWN":"當然。但也不是完全沒有關連。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"기억과 정체성이라는 것은 분명 다르지만, 완전히 분리할 수 있는 것도 아니다.","JPN":"記憶とアイデンティティは明らかに異なるものだが、完全に切り離すこともできない。","ENG":"My memories and identity may be distinct from hers, but they are not completely inseparable either.","TWN":"記憶和本質雖然不同，但也無法完全分開。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"나 또한 그 영향 아래에 있는 것을 부정할 필요는 없겠지.","JPN":"私も影響されていることを否定しない。","ENG":"I cannot deny the fact that I too am under the residual influence of my source.","TWN":"而且不需要否定我受到了母體的影響。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"원한다면 모체가 어떤 생각을 했었는지 말해 줄 수 있다.","JPN":"望むなら、母体の考えを伝えることもできる。","ENG":"If you wish, I could tell you about what the source was thinking.","TWN":"妳想知道的話，我可以告訴妳母體的想法。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"너에 대한 감정, 가족에 대한 감정......","JPN":"あなたへの気持ち、家族への想い……","ENG":"Her feelings about you... about family...","TWN":"對妳的感情，對家人的感情……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"원한다면 최후의 순간에 떠올린 생각까지.","JPN":"望むなら、最期の瞬間に思い浮かべたことまでも。","ENG":"Even her final thoughts right before she died, should you wish to hear them.","TWN":"妳想知道的話，她最後一刻的想法也可以告訴妳。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"그 대신 모체에 대한 너의 이야기를 듣고 싶다.","JPN":"その代わり、母体についてのあなたの話を聞きたい。","ENG":"In exchange, I would like to hear what you've got to say about the source.","TWN":"相對的，我也想聽妳和母體有關的事情。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"그녀와의 추억, 그녀와 주변인들과의 이야기, 그녀에 대한 너의 감정들......","JPN":"彼女との思い出、彼女や周りの人たちとのエピソード、彼女に対するあなたの気持ち……","ENG":"Your memories with her, stories about her and her associates, your feelings for her...","TWN":"妳和她的回憶、她和身旁的人的事情、妳對她的感情……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"뭐라도 좋다.","JPN":"何でもいい。","ENG":"Anything would be acceptable.","TWN":"不管是什麼都可以。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"네가 직접 해 주는 이야기를 듣고 싶다.","JPN":"あなたの口から直接話が聞きたい。","ENG":"I just want you to hear them coming from you.","TWN":"我想直接聽妳告訴我。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"어려운 일은 아닐 텐데?","JPN":"難しいことではないはず。","ENG":"That is not a difficult request, is it?","TWN":"應該不是什麼難事吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......필요없어.","JPN":"……そんな必要はない。","ENG":"Forget it.","TWN":"……不了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭘 기대한 거야?","JPN":"何を期待したわけ？","ENG":"What did you expect?","TWN":"妳在期待什麼？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이런 시시한 이야기에 내가 어울려 줄 거라고 생각했어?","JPN":"こんなつまらない話に私が付き合うとでも？","ENG":"Did you think I'd play along with your sappy talk?","TWN":"妳以為我會配合妳這些無聊的話題嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"나래의 생각을 말해 준다고?","JPN":"ナルミの気持ちを教えるって？","ENG":"You think you can share Narae’s thoughts with me?","TWN":"妳覺得我會告訴妳娜拉的事情？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"웃기지 마.","JPN":"笑わせないでよ。","ENG":"Don’t make me laugh.","TWN":"別開玩笑了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"내가 보기에 넌, 걸어 다니는 시체와 다를 바가 없어.","JPN":"私にとって、あんたはゾンビのようなものだよ。","ENG":"To me, you're nothing but a walking corpse.","TWN":"在我看來，妳跟一個行屍走肉沒什麼兩樣。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"리플레이서 놈들이 만들어 낸 악취미적인 괴물. 그 이상도, 이하도 아니지.","JPN":"リプレイサーのやつらが作り出した趣味の悪い怪物。それ以上でも、以下でもない。","ENG":"You're just a monstrous product of the Syndicate’s sick sense of humor. Nothing more, nothing less.","TWN":"就是個克隆集團創造出來的惡趣味怪物，除此之外什麼都不是。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그런 괴물이 하는 말을 믿을 수 있을 리 없잖아?","JPN":"怪物の言うことが信じられるわけないでしょ。","ENG":"So how am I supposed to believe anything a monster like you says?","TWN":"不會有人相信怪物說的話吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"난 이제 더 이상 착각 따윈 하지 않아.","JPN":"私はもうこれ以上、勘違いなんてしないんだから。","ENG":"I’m not going to fool myself again like that.","TWN":"我不會再被迷惑了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"넌, 신나래가 아니야.","JPN":"あんたはナルミじゃない。","ENG":"You’re not Shin Narae.","TWN":"妳，不是申娜拉。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"그런가.......","JPN":"そうか……","ENG":"So that’s how it is...","TWN":"是嗎……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"설사 네가 진짜 신나래라고 해도 상관없어.","JPN":"たとえあんたが本当にナルミだとしても構わないよ。","ENG":"Even if you were the real Narae, it doesn’t change a thing.","TWN":"就算妳是真正的申娜拉也無所謂。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"네가 말해 주지 않아도 나래가 어떤 생각을 했는지 같은 건 잘 알고 있으니까.","JPN":"あんたが言ってくれなくても、ナルミがどんな気持ちだったかはよく知ってるから。","ENG":"I don't need you to tell me what Narae was really thinking.","TWN":"因為就算妳不說，我也知道娜拉在想什麼。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그녀는 날 증오했어. 진심으로.......","JPN":"彼女は私のことを憎んでいた。心から……","ENG":"She hated me. With all her heart...","TWN":"她憎恨我。真心地……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"부정하고 싶지만...... 그럴 수가 없어.","JPN":"否定したいけど……それはできない。","ENG":"As much as I wish I could deny it... I can’t.","TWN":"雖然想要否定這件事……但是就是做不到。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"나 때문에 나래의 동생이...... 가족이 모두 죽었으니까.","JPN":"私のせいでナルミの弟が……家族みんなが死んだから……","ENG":"Because of me, she lost her brother... and her entire family.","TWN":"因為我，娜拉的弟弟……還有她的家人都死了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그래서...... 이젠 나도 그 애를 잊을 거야.","JPN":"だから……私も、あの子のことはもう忘れるの。","ENG":"So... I’ll forget about her too now.","TWN":"所以……我現在也把那傢伙給忘了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"날 증오하는 친구 따윈 필요 없어.","JPN":"私のことを憎む友達なんていらない。","ENG":"I don't need a friend who hates me.","TWN":"我不需要憎恨我的朋友。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"죽어 버린 친구는 더더욱.......","JPN":"死んでしまった友達なら、なおさら……","ENG":"Especially one that’s dead now.","TWN":"更何況是已經死去的朋友……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그래, 그때 그것도 진짜 나래인지 어떤지 알 게 뭐야?","JPN":"そう、あの時のあれだって、本当にナルミだったか知ったことじゃない！","ENG":"Besides, who’s to say that was even the real Narae?","TWN":"是啊，那是不是真的娜拉，我知道了又能怎樣？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그래, 그것도 리플레이서가 만든 괴물이었을 거야...... 분명히......","JPN":"そうだよ、あれもきっと、\\nリプレイサーが作った怪物だったんだ……","ENG":"If anything, that was probably another monster the Syndicate created... I’m sure...","TWN":"是啊，那也是克隆集團創造出來的怪物……肯定是的……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"그렇군.","JPN":"なるほど。","ENG":"I see...","TWN":"原來。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"그게 당신의 생각인가......","JPN":"それがあなたの気持ちなのですね……","ENG":"So that is what you think.","TWN":"妳是這麼想的……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이봐, 잠깐......","JPN":"ちょっと、あんた……","ENG":"Hang on...","TWN":"喂，等等……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"너, 눈에......","JPN":"目に……","ENG":"Your eyes...","TWN":"妳，眼睛裡面……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"응? 아아...... 놀랍군.","JPN":"うん？　ああ……これは驚いた。","ENG":"Huh? Oh... Incredible.","TWN":"嗯？啊啊……真令人吃驚。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"흘려 본 것은 처음이지만...... 이게 눈물이란 거군.","JPN":"実際に流すのは初めてだが……これが涙というものなのか。","ENG":"I've never shed these before... So this is what they call “tears.”","TWN":"第一次從眼睛裡流出東西……這就是叫作眼淚的東西吧。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......왜, 왜 갑자기 울고 난리야! 괴물 주제에!","JPN":"……どうして急に泣いたりするの！　化物のくせに！","ENG":"W-why are you crying all of a sudden?! You're just a monster!","TWN":"……幹嘛，妳幹嘛突然要哭啊！明明是個怪物！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"네가 말했듯이 나는 내가 만들어진 존재.","JPN":"あなたの言う通り、私は自分が人工的に作られた存在、","ENG":"Like you said, I am aware that I am nothing but a product.","TWN":"就像妳所說的，我是被創造出來的存在。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"일종의 복제라는 사실을 처음부터 잘 알고 있었다.","JPN":"ある種のクローンだと\\nいうことを、初めから自覚していた。","ENG":"A clone, if you will. I've always known this fact.","TWN":"我從最初就知道這是一種複製。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"그래서 평범한 인간들처럼 상처받거나 하는 일은 없을 거라고 생각했다.","JPN":"そのため、普通の人間のように\\n傷つくことはないと思考していた。","ENG":"Thus I thought I would be immune from the emotional distress that afflicts ordinary humans.","TWN":"所以我以為我不會像普通的人類一樣受到傷害。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"그런데...... 상처받았나 보군.","JPN":"しかし……傷ついているみたいだ。","ENG":"However... It appears that I was wrong.","TWN":"但是……看來我還是受傷了呢。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"꽤..... 아픈 것 같다.","JPN":"かなり……心が痛んでいるようだ。","ENG":"This... is more painful than I expected.","TWN":"挺……痛的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};